functions.example_code:
-- 统计总行数
SELECT COUNT(*) AS total FROM users;

-- 统计非空城市数
SELECT COUNT(city) AS has_city FROM users;

-- 统计去重城市数
SELECT COUNT(DISTINCT city) AS unique_cities FROM users;

-- 计算所有订单总金额
SELECT SUM(amount) AS total_amount FROM orders;

-- 按用户分组求和
SELECT user_id, SUM(amount) AS total_spent FROM orders GROUP BY user_id;

SELECT name, score,
  RANK() OVER (ORDER BY score DESC) AS rk
FROM students;

SELECT name, score,
  DENSE_RANK() OVER (ORDER BY score DESC) AS dr
FROM students;

SELECT sale_date, amount,
  LAG(amount, 1) OVER (ORDER BY sale_date) AS prev_amount
FROM daily_sales;

SELECT sale_date, amount,
  LEAD(amount, 1) OVER (ORDER BY sale_date) AS next_amount
FROM daily_sales;

SELECT CURRENT_DATE;

-- 查询今日订单
SELECT * FROM orders WHERE order_date = CURRENT_DATE;

SELECT CAST('123' AS INT) AS n;
SELECT CAST('2024-01-15' AS DATE) AS d;
SELECT CAST(42 AS DECIMAL(10,2));

-- 收集每个城市下的用户名为数组
SELECT city, COLLECT_LIST(name) AS users
FROM users GROUP BY city;

-- 收集每个城市下的去重用户名
SELECT city, COLLECT_SET(name) AS unique_users
FROM users GROUP BY city;

SELECT PERCENTILE_APPROX(amount, 0.95) AS p95 FROM orders;

-- 一次取多个分位
SELECT PERCENTILE_APPROX(amount, ARRAY(0.5,0.9,0.99)) FROM orders;

SELECT id, pos, tag
FROM articles
LATERAL VIEW POSEXPLODE(tags) t AS pos, tag;

SELECT uid, name, age
FROM users
LATERAL VIEW JSON_TUPLE(profile, 'name', 'age') t AS name, age;

SELECT a, b
FROM t
LATERAL VIEW INLINE(struct_arr) v AS a, b;
